import { Component, OnInit } from '@angular/core';
import { RestaurantService } from '../../../services/restaurant.service';
import { Restaurant } from '../../../models/food.model';

@Component({
    selector: 'app-approve-restaurants',
    templateUrl: './approve-restaurants.component.html',
    styleUrls: ['./approve-restaurants.component.css']
})
export class ApproveRestaurantsComponent implements OnInit {
    restaurants: Restaurant[] = [];
    loading = true;
    error = '';

    constructor(private restaurantService: RestaurantService) { }

    ngOnInit() {
        this.loadRestaurants();
    }

    loadRestaurants() {
        this.loading = true;
        this.restaurantService.getAdminAll().subscribe({
            next: (data) => {
                this.restaurants = data;
                this.loading = false;
            },
            error: (err) => {
                this.error = 'Failed to load restaurants';
                this.loading = false;
            }
        });
    }

    approveRestaurant(id: string | undefined) {
        if (!id) return;
        this.restaurantService.approve(id).subscribe({
            next: () => {
                const rest = this.restaurants.find(r => r._id === id);
                if (rest) rest.isApproved = true;
            },
            error: (err) => {
                this.error = 'Failed to approve restaurant';
            }
        });
    }
}
<div class="admin-page fade-in">
    <div class="admin-header">
        <h2>Approve Restaurants</h2>
        <p>Review and approve new restaurant registrations</p>
    </div>

    <div class="alert alert-error" *ngIf="error">{{error}}</div>

    <div *ngIf="loading" class="loading">Loading restaurants...</div>

    <div class="table-container" *ngIf="!loading">
        <table class="admin-table">
            <thead>
                <tr>
                    <th>Name</th>
                    <th>Cuisine</th>
                    <th>Status</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                <tr *ngFor="let restaurant of restaurants">
                    <td>{{restaurant.name}}</td>
                    <td>{{restaurant.cuisineType}}</td>
                    <td>
                        <span class="status-badge" [class.status-approved]="restaurant.isApproved" [class.status-pending]="!restaurant.isApproved">
                            {{restaurant.isApproved ? 'Approved' : 'Pending'}}
                        </span>
                    </td>
                    <td>
                        <button class="btn btn-sm btn-primary" (click)="approveRestaurant(restaurant._id)" [disabled]="restaurant.isApproved">
                            {{restaurant.isApproved ? 'Approved' : 'Approve'}}
                        </button>
                    </td>
                </tr>
                <tr *ngIf="restaurants.length === 0">
                    <td colspan="4" class="text-center">No restaurants found.</td>
                </tr>
            </tbody>
        </table>
    </div>
</div>
